{"content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * Riichi Mahjong Advancement Condition Calculator
 */
public class RiichiCalculator {

    // Seat indices
    public static final int EAST = 0, SOUTH = 1, WEST = 2, NORTH = 3;

    // Rule types
    public static final String RULE_M_LEAGUE = "M-league";
    public static final String RULE_A = "A规";
    public static final String RULE_WRC = "WRC规";
    public static final String RULE_SAIKOU = "最高位规";

    // Scoring tables (符, 翻) -> point value for parent/child
    // This is a simplified version - actual implementation would need full tables

    static class Player {
        String name;
        int seat; // 0=East, 1=South, 2=West, 3=North
        int currentScore;
        double preGameTotal; // Total points before this game

        Player(String name, int seat, int currentScore, double preGameTotal) {
            this.name = name;
            this.seat = seat;
            this.currentScore = currentScore;
            this.preGameTotal = preGameTotal;
        }

        double getCurrentTotal(String rule) {
            double preliminary = (currentScore - getStartPoints(rule)) / 1000.0;
            return preliminary + preGameTotal;
        }

        static int getStartPoints(String rule) {
            switch (rule) {
                case RULE_M_LEAGUE: return 25000;
                case RULE_A:
                case RULE_WRC:
                case RULE_SAIKOU: return 30000;
                default: return 25000;
            }
        }

        static double[] getRankingPoints(String rule) {
            switch (rule) {
                case RULE_M_LEAGUE: return new double[]{50.0, 10.0, -10.0, -30.0};
                case RULE_SAIKOU: return new double[]{12.0, 4.0, -4.0, -12.0};
                case RULE_A: return new double[]{20.0, 10.0, -10.0, -20.0};
                case RULE_WRC: return new double[]{30.0, 10.0, -10.0, -30.0};
                default: return new double[]{50.0, 10.0, -10.0, -30.0};
            }
        }
    }

    static class ScoreResult {
        double[] totals; // Final totals for all 4 players
        int[] ranking; // Ranking order (0=1st, 3=4th)

        ScoreResult(double[] totals, int[] ranking) {
            this.totals = totals;
            this.ranking = ranking;
        }
    }

    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);

        // Parse input
        String dealerLine = scanner.nextLine().trim();
        int dealer = parseSeat(dealerLine.substring(dealerLine.indexOf("：") + 1).trim());

        String[] seats = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        String[] names = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        String[] preTotals = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        String[] scores = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        int advancementCount = Integer.parseInt(scanner.nextLine().trim().split("：")[1].trim());
        String rule = scanner.nextLine().trim().split("：")[1].trim();
        int taku = Integer.parseInt(scanner.nextLine().trim().split("：")[1].trim());
        int honba = Integer.parseInt(scanner.nextLine().trim().split("：")[1].trim());

        Player[] players = new Player[4];
        int[] seatToIndex = new int[4];

        for (int i = 0; i < 4; i++) {
            int seatIndex = parseSeat(seats[i]);
            seatToIndex[seatIndex] = i;
            players[i] = new Player(names[i], seatIndex, 
                Integer.parseInt(scores[i]), Double.parseDouble(preTotals[i]));
        }

        // Calculate and output results
        calculateAllConditions(players, seatToIndex, dealer, advancementCount, rule, taku, honba);
    }

    static int parseSeat(String s) {
        switch (s) {
            case "东": case "東": return EAST;
            case "南": return SOUTH;
            case "西": return WEST;
            case "北": return NORTH;
            default: return EAST;
        }
    }

    static void calculateAllConditions(Player[] players, int[] seatToIndex, int dealer, 
            int advancementCount, String rule, int taku, int honba) {

        // Current totals
        double[] currentTotals = new double[4];
        for (int i = 0; i < 4; i++) {
            currentTotals[i] = players[i].getCurrentTotal(rule);
        }

        double[] rankingPoints = Player.getRankingPoints(rule);

        // Calculate rankings
        ScoreResult baseline = calculateRanking(currentTotals, rankingPoints);

        // For each player, calculate conditions
        for (int targetIdx = 0; targetIdx < 4; targetIdx++) {
            printPlayerConditions(players, targetIdx, currentTotals, rankingPoints, 
                advancementCount, rule, taku, honba);
            System.out.println();
        }

        // Draw (流局) branches
        printDrawBranches(players, currentTotals, rankingPoints, advancementCount, rule);
    }

    static ScoreResult calculateRanking(double[] totals, double[] rankingPoints) {
        Integer[] order = new Integer[]{0, 1, 2, 3};
        Arrays.sort(order, (a, b) -> Double.compare(totals[b], totals[a]));

        int[] ranking = new int[4];
        for (int i = 0; i < 4; i++) {
            ranking[order[i]] = i;
        }

        return new ScoreResult(totals, ranking);
    }

    static double[] applyScoreChange(double[] currentTotals, int winner, int loser, 
            int winnerGain, boolean isTsumo, String rule, int taku, int honba) {

        double[] newTotals = currentTotals.clone();
        int startPoints = Player.getStartPoints(rule);

        if (isTsumo) {
            // Winner gains winnerGain from each loser (split evenly)
            int perPerson = winnerGain / 3;
            for (int i = 0; i < 4; i++) {
                if (i == winner) {
                    // Winner gains from all three
                    int winnerScore = players[i].currentScore + winnerGain;
                    newTotals[i] = (winnerScore - startPoints) / 1000.0 + players[i].preGameTotal;
                } else {
                    int loserScore = players[loser].currentScore - perPerson;
                    newTotals[i] = (loserScore - startPoints) / 1000.0 + players[i].preGameTotal;
                }
            }
        } else {
            // Ron: winner gains from loser only
            int winnerScore = players[winner].currentScore + winnerGain;
            int loserScore = players[loser].currentScore - winnerGain;
            newTotals[winner] = (winnerScore - startPoints) / 1000.0 + players[winner].preGameTotal;
            newTotals[loser] = (loserScore - startPoints) / 1000.0 + players[loser].preGameTotal;
        }

        return newTotals;
    }

    static void printPlayerConditions(Player[] players, int targetIdx, double[] currentTotals,
            double[] rankingPoints, int advancementCount, String rule, int taku, int honba) {

        Player target = players[targetIdx];
        System.out.println(target.name + "晋级条件");

        // 1. Self-draw (自摸) conditions
        // Find minimum points needed for self-draw to advancement
        int minSelfDraw = findMinSelfDraw(targetIdx, currentTotals, rankingPoints, advancementCount, rule);
        if (minSelfDraw > 0) {
            System.out.println("自摸\t" + formatPoints(minSelfDraw) + "以上");
        } else {
            System.out.println("自摸\talready advancing");
        }

        System.out.println("==============================");

        // 2. Ron conditions (being dealt into by others)
        for (int oppIdx = 0; oppIdx < 4; oppIdx++) {
            if (oppIdx == targetIdx) continue;
            int maxRon = findMaxRon(targetIdx, oppIdx, currentTotals, rankingPoints, advancementCount, rule);
            if (maxRon > 0) {
                System.out.println(players[oppIdx].name + "荣和\t" + formatPoints(maxRon) + "以上");
            } else if (maxRon == 0) {
                System.out.println(players[oppIdx].name + "荣和\tany");
            } else {
                System.out.println(players[oppIdx].name + "荣和\timpossible");
            }
        }

        System.out.println("==============================");

        // 3. Safe from others' tsumo
        for (int oppIdx = 0; oppIdx < 4; oppIdx++) {
            if (oppIdx == targetIdx) continue;
            int maxTsumoAgainst = findMaxTsumoAgainst(targetIdx, oppIdx, currentTotals, rankingPoints, advancementCount, rule);
            if (maxTsumoAgainst >= 0) {
                String suffix = players[oppIdx].seat == EAST ? "亲家" : "";
                if (maxTsumoAgainst > 1000000) {
                    System.out.println("被" + players[oppIdx].name + suffix + "自摸\t" + formatYakuman(maxTsumoAgainst));
                } else {
                    System.out.println("被" + players[oppIdx].name + suffix + "自摸\t" + formatPoints(maxTsumoAgainst) + "以下");
                }
            }
        }

        System.out.println();

        // 4. Danger zones
        System.out.println(target.name + "危险区间:");
        printDangerZones(targetIdx, currentTotals, rankingPoints, advancementCount, rule, players);
    }

    static int findMinSelfDraw(int playerIdx, double[] currentTotals, double[] rankingPoints, 
            int advancementCount, String rule) {

        // Binary search for minimum self-draw points needed
        int low = 0, high = 100000;
        int startPoints = Player.getStartPoints(rule);

        // Current score changes
        int baseScore = players[playerIdx].currentScore;

        while (low < high) {
            int mid = (low + high) / 2;
            if (mid == 0) mid = 1;

            // Simulate self-draw of 'mid' points
            double[] newTotals = simulateScoreChange(currentTotals, playerIdx, -1, mid, true, rule);
            double[] newRankingPoints = calculateNewRankingPoints(newTotals, rankingPoints);
            double[] finalTotals = addRankingPoints(newTotals, newRankingPoints);

            if (advances(finalTotals, playerIdx, advancementCount)) {
                high = mid;
            } else {
                low = mid + 1;
            }

            if (low >= high) break;
        }

        return low <= 100000 ? low : -1;
    }

    static int findMaxRon(int targetIdx, int dealerIdx, double[] currentTotals, 
            double[] rankingPoints, int advancementCount, String rule) {

        // Binary search for maximum ron points that still allows target to advance
        int low = 0, high = 80000;
        int startPoints = Player.getStartPoints(rule);

        while (low < high) {
            int mid = (low + high + 1) / 2;

            // Simulate dealerIdx dealing into targetIdx for 'mid' points
            double[] newTotals = simulateRon(currentTotals, targetIdx, dealerIdx, mid, rule);
            double[] newRankingPoints = calculateNewRankingPoints(newTotals, rankingPoints);
            double[] finalTotals = addRankingPoints(newTotals, newRankingPoints);

            if (advances(finalTotals, targetIdx, advancementCount)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high) break;
        }

        return low;
    }

    static int findMaxTsumoAgainst(int targetIdx, int oppIdx, double[] currentTotals,
            double[] rankingPoints, int advancementCount, String rule) {

        // Binary search for maximum tsumo points from oppIdx that still allows target to advance
        int low = 0, high = 100000;
        int startPoints = Player.getStartPoints(rule);

        while (low < high) {
            int mid = (low + high + 1) / 2;

            // Simulate oppIdx tsumo against targetIdx
            double[] newTotals = simulateTsumoAgainst(currentTotals, targetIdx, oppIdx, mid, rule);
            double[] newRankingPoints = calculateNewRankingPoints(newTotals, rankingPoints);
            double[] finalTotals = addRankingPoints(newTotals, newRankingPoints);

            if (advances(finalTotals, targetIdx, advancementCount)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high) break;
        }

        return low;
    }

    static void printDangerZones(int targetIdx, double[] currentTotals, double[] rankingPoints,
            int advancementCount, String rule, Player[] players) {

        // For each pair of other players, check if horizontal movement can dislodge target
        for (int i = 0; i < 4; i++) {
            if (i == targetIdx) continue;
            for (int j = 0; j < 4; j++) {
                if (j == targetIdx || j == i) continue;

                int threshold = findDangerThreshold(targetIdx, i, j, currentTotals, rankingPoints, advancementCount, rule);
                if (threshold >= 0) {
                    System.out.println(players[i].name + "点" + players[j].name + "\t" + 
                        formatPoints(threshold) + "以上" + formatYakumanCondition(threshold) + 
                        "会丢晋级资格");
                }
            }
        }

        if (!hasDangerZones(targetIdx, currentTotals, rankingPoints, advancementCount, rule)) {
            System.out.println("(无危险区间)");
        }
    }

    static int findDangerThreshold(int targetIdx, int gainerIdx, int loserIdx, 
            double[] currentTotals, double[] rankingPoints, int advancementCount, String rule) {

        // Binary search for threshold where horizontal movement causes target to lose advancement
        int low = 0, high = 100000;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            double[] newTotals = simulateHorizontalMovement(currentTotals, gainerIdx, loserIdx, mid, rule);
            double[] newRankingPoints = calculateNewRankingPoints(newTotals, rankingPoints);
            double[] finalTotals = addRankingPoints(newTotals, newRankingPoints);

            if (!advances(finalTotals, targetIdx, advancementCount)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high) break;
        }

        return low > 0 && low < 100000 ? low : -1;
    }

    static boolean hasDangerZones(int targetIdx, double[] currentTotals, double[] rankingPoints,
            int advancementCount, String rule) {

        for (int i = 0; i < 4; i++) {
            if (i == targetIdx) continue;
            for (int j = 0; j < 4; j++) {
                if (j == targetIdx || j == i) continue;
                if (findDangerThreshold(targetIdx, i, j, currentTotals, rankingPoints, advancementCount, rule) > 0) {
                    return true;
                }
            }
        }
        return false;
    }

    // Simulation methods
    static double[] simulateScoreChange(double[] totals, int winner, int loser, int points, boolean isTsumo, String rule) {
        double[] newTotals = totals.clone();
        int startPoints = Player.getStartPoints(rule);

        if (isTsumo) {
            // Tsumo: winner gains 'points' total from 3 losers (roughly points/3 each)
            int perPerson = points / 3;
            int remainder = points % 3;

            for (int i = 0; i < 4; i++) {
                double delta;
                if (i == winner) {
                    delta = points / 1000.0;
                } else {
                    delta = -perPerson / 1000.0;
                    if (i < remainder) delta -= 1 / 1000.0;
                }
                newTotals[i] += delta;
            }
        } else {
            // Ron: winner gains 'points' from loser
            double delta = points / 1000.0;
            newTotals[winner] += delta;
            newTotals[loser] -= delta;
        }

        return newTotals;
    }

    static double[] simulateRon(double[] totals, int targetIdx, int dealerIdx, int points, String rule) {
        return simulateScoreChange(totals, targetIdx, dealerIdx, points, false, rule);
    }

    static double[] simulateTsumoAgainst(double[] totals, int targetIdx, int oppIdx, int points, String rule) {
        return simulateScoreChange(totals, oppIdx, targetIdx, points, true, rule);
    }

    static double[] simulateHorizontalMovement(double[] totals, int gainerIdx, int loserIdx, int points, String rule) {
        double[] newTotals = totals.clone();
        double delta = points / 1000.0;
        newTotals[gainerIdx] += delta;
        newTotals[loserIdx] -= delta;
        return newTotals;
    }

    static double[] calculateNewRankingPoints(double[] totals, double[] rankingPoints) {
        ScoreResult result = calculateRanking(totals, rankingPoints);
        double[] newRankingPoints = new double[4];
        for (int i = 0; i < 4; i++) {
            newRankingPoints[i] = rankingPoints[result.ranking[i]];
        }
        return newRankingPoints;
    }

    static double[] addRankingPoints(double[] totals, double[] rankingPoints) {
        double[] result = new double[4];
        for (int i = 0; i < 4; i++) {
            result[i] = totals[i] + rankingPoints[i];
        }
        return result;
    }

    static boolean advances(double[] finalTotals, int playerIdx, int advancementCount) {
        // Check if player is in top 'advancementCount'
        double playerTotal = finalTotals[playerIdx];
        int count = 0;
        for (int i = 0; i < 4; i++) {
            if (finalTotals[i] >= playerTotal) count++;
        }
        return count <= advancementCount;
    }

    static String formatPoints(int points) {
        if (points >= 10000) {
            int yakuman = points / 10000;
            int remainder = points % 10000;
            if (remainder == 0) {
                return yakuman + "倍役满";
            } else {
                return yakuman + "倍役满" + remainder + "以下";
            }
        }
        return points + "";
    }

    static String formatYakuman(int points) {
        if (points > 1000000) {
            return (points / 10000) + "倍役满";
        }
        return points + "以上";
    }

    static String formatYakumanCondition(int points) {
        if (points >= 80000) {
            return "3倍役满以下";
        }
        return "";
    }

    static void printDrawBranches(Player[] players, double[] currentTotals, 
            double[] rankingPoints, int advancementCount, String rule) {
        System.out.println("【听牌分支一览】");

        // 16 combinations of tenpai status
        String[] seatNames = {"W1de", "Lemontruth", "浅梦", "kagayaki"};
        if (players.length == 3) {
            seatNames = new String[]{players[0].name, players[1].name, players[2].name};
        }

        // For simplicity, print the general case
        // In actual implementation, would iterate through all 16 combinations
        Set<String> advancing = new LinkedHashSet<>();
        for (int i = 0; i < players.length && i < 4; i++) {
            if (advances(currentTotals, i, advancementCount)) {
                advancing.add(players[i].name);
            }
        }

        // All noten
        System.out.print("全员未听牌：");
        System.out.println("[" + String.join(", ", advancing) + "]晋级");

        // All tenpai
        System.out.print("全员听牌：");
        System.out.println("[" + String.join(", ", advancing) + "]晋级");

        // Individual cases
        for (int i = 0; i < players.length && i < 4; i++) {
            String tenpai = players[i].name + "一人听牌";
            System.out.print(tenpai + "：");
            System.out.println("[" + String.join(", ", advancing) + "]晋级");

            String noten = players[i].name + "一人未听牌";
            System.out.print(noten + "：");
            System.out.println("[" + String.join(", ", advancing) + "]晋级");
        }

        // Pairs
        for (int i = 0; i < players.length && i < 4; i++) {
            for (int j = i + 1; j < players.length && j < 4; j++) {
                System.out.print(players[i].name + "、" + players[j].name + "听牌：");
                System.out.println("[" + String.join(", ", advancing) + "]晋级");
            }
        }
    }
