{"content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * Riichi Mahjong Advancement Condition Calculator
 * 
 * 支持规则: M-League, A规, WRC规, 最高位规
 */
public class RiichiCalculator {

    public static final int EAST = 0, SOUTH = 1, WEST = 2, NORTH = 3;

    public static final String RULE_M_LEAGUE = "M-league";
    public static final String RULE_A = "A规";
    public static final String RULE_WRC = "WRC规";
    public static final String RULE_SAIKOU = "最高位规";

    public static final int YAKUMAN = 80000;
    public static final int DOUBLE_YAKUMAN = 160000;
    public static final int TRIPLE_YAKUMAN = 240000;

    static class Player {
        String name;
        int seat;
        int currentScore;
        double preGameTotal;

        Player(String name, int seat, int currentScore, double preGameTotal) {
            this.name = name;
            this.seat = seat;
            this.currentScore = currentScore;
            this.preGameTotal = preGameTotal;
        }
    }

    static class ScoreResult {
        double[] preliminary;
        int[] ranking;
        double[] finalTotals;
        int[] scores;

        ScoreResult(double[] preliminary, int[] ranking, double[] finalTotals, int[] scores) {
            this.preliminary = preliminary;
            this.ranking = ranking;
            this.finalTotals = finalTotals;
            this.scores = scores;
        }
    }

    static Player[] players;
    static String rule;
    static int advancementCount;
    static int startPoints;
    static double[] rankingPoints;
    static int dealer;
    static int taku;
    static int honba;

    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);

        List<String> lines = new ArrayList<>();
        while (scanner.hasNextLine()) {
            String line = scanner.nextLine();
            if (line.trim().isEmpty()) continue;
            lines.add(line);
        }

        if (lines.size() < 9) {
            System.err.println("Error: Insufficient input lines");
            return;
        }

        dealer = parseSeat(getValue(lines.get(0)));
        String[] seats = getValue(lines.get(1)).trim().split("\\s+");
        String[] names = getValue(lines.get(2)).trim().split("\\s+");
        String[] preTotals = getValue(lines.get(3)).trim().split("\\s+");
        String[] scores = getValue(lines.get(4)).trim().split("\\s+");
        advancementCount = Integer.parseInt(getValue(lines.get(5)).trim());
        rule = getValue(lines.get(6)).trim();
        taku = Integer.parseInt(getValue(lines.get(7)).trim());
        honba = Integer.parseInt(getValue(lines.get(8)).trim());

        players = new Player[4];
        for (int i = 0; i < 4; i++) {
            int seatIndex = parseSeat(seats[i]);
            players[i] = new Player(names[i], seatIndex, 
                Integer.parseInt(scores[i]), Double.parseDouble(preTotals[i]));
        }

        startPoints = getStartPoints(rule);
        rankingPoints = getRankingPoints(rule);

        ScoreResult baseline = calculateCurrentResult();

        for (int targetIdx = 0; targetIdx < 4; targetIdx++) {
            printPlayerConditions(targetIdx, baseline);
            System.out.println();
        }

        printDrawBranches(baseline);
    }

    static String getValue(String line) {
        int colonPos = line.lastIndexOf(':');
        int fullwidthColonPos = line.lastIndexOf('：');
        int pos = Math.max(colonPos, fullwidthColonPos);
        if (pos >= 0 && pos < line.length() - 1) {
            return line.substring(pos + 1);
        }
        return line;
    }

    static int parseSeat(String s) {
        switch (s) {
            case "东": case "東": return EAST;
            case "南": return SOUTH;
            case "西": return WEST;
            case "北": return NORTH;
            default: return EAST;
        }
    }

    static int getStartPoints(String rule) {
        switch (rule) {
            case RULE_M_LEAGUE: return 25000;
            case RULE_A:
            case RULE_WRC:
            case RULE_SAIKOU: return 30000;
            default: return 25000;
        }
    }

    static double[] getRankingPoints(String rule) {
        switch (rule) {
            case RULE_M_LEAGUE: return new double[]{50.0, 10.0, -10.0, -30.0};
            case RULE_SAIKOU: return new double[]{12.0, 4.0, -4.0, -12.0};
            case RULE_A: return new double[]{20.0, 10.0, -10.0, -20.0};
            case RULE_WRC: return new double[]{30.0, 10.0, -10.0, -30.0};
            default: return new double[]{50.0, 10.0, -10.0, -30.0};
        }
    }

    static ScoreResult calculateCurrentResult() {
        return calculateWithScores(new int[]{
            players[0].currentScore, players[1].currentScore, 
            players[2].currentScore, players[3].currentScore
        });
    }

    static ScoreResult calculateWithScores(int[] scores) {
        double[] preliminary = new double[4];
        for (int i = 0; i < 4; i++) {
            preliminary[i] = (scores[i] - startPoints) / 1000.0;
        }

        double[] totals = new double[4];
        for (int i = 0; i < 4; i++) {
            totals[i] = preliminary[i] + players[i].preGameTotal;
        }

        int[] ranking = calculateRanking(totals);

        double[] finalTotals = new double[4];
        for (int i = 0; i < 4; i++) {
            finalTotals[i] = totals[i] + rankingPoints[ranking[i]];
        }

        return new ScoreResult(preliminary, ranking, finalTotals, scores);
    }

    static int[] calculateRanking(double[] totals) {
        Integer[] order = new Integer[]{0, 1, 2, 3};
        Arrays.sort(order, (a, b) -> Double.compare(totals[b], totals[a]));

        int[] ranking = new int[4];
        for (int i = 0; i < 4; i++) {
            ranking[order[i]] = i;
        }
        return ranking;
    }

    static boolean advances(ScoreResult result, int playerIdx) {
        double playerTotal = result.finalTotals[playerIdx];
        int count = 0;
        for (int i = 0; i < 4; i++) {
            if (result.finalTotals[i] >= playerTotal - 0.001) count++;
        }
        return count <= advancementCount;
    }

    static int[] simulateTsumo(int[] baseScores, int winner, int points) {
        int[] newScores = baseScores.clone();
        int perPerson = points / 3;
        int remainder = points % 3;
        newScores[winner] += points;
        int idx = 0;
        for (int i = 0; i < 3; i++) {
            int loserIdx = (winner + i + 1) % 4;
            int payment = perPerson + (idx < remainder ? 1 : 0);
            newScores[loserIdx] -= payment;
            idx++;
        }
        return newScores;
    }

    static int[] simulateRon(int[] baseScores, int winner, int loser, int points) {
        int[] newScores = baseScores.clone();
        newScores[winner] += points;
        newScores[loser] -= points;
        return newScores;
    }

    static int[] simulateHorizontal(int[] baseScores, int giver, int receiver, int points) {
        int[] newScores = baseScores.clone();
        newScores[receiver] += points;
        newScores[giver] -= points;
        return newScores;
    }

    static void printPlayerConditions(int targetIdx, ScoreResult baseline) {
        Player target = players[targetIdx];
        System.out.println(target.name + "晋级条件");

        // 1. Self-draw conditions
        int minTsumo = findMinTsumo(targetIdx, baseline);
        if (minTsumo > 0 && minTsumo < YAKUMAN) {
            int childPay = minTsumo / 3;
            int parentPay = minTsumo / 3;
            System.out.println("自摸\t" + childPay + "・" + parentPay + "以上");
        } else if (minTsumo >= YAKUMAN) {
            System.out.println("自摸\t" + formatYakuman() + "以上");
        } else {
            System.out.println("自摸\talready advancing");
        }

        System.out.println("==============================");

        // 2. Ron conditions when others deal into target
        for (int oppIdx = 0; oppIdx < 4; oppIdx++) {
            if (oppIdx == targetIdx) continue;
            int minRon = findMinRonForTarget(targetIdx, oppIdx, baseline);
            if (minRon >= YAKUMAN) {
                System.out.println(players[oppIdx].name + "荣和\t" + formatYakuman() + "以上");
            } else if (minRon > 0) {
                System.out.println(players[oppIdx].name + "荣和\t" + minRon + "以上");
            } else {
                System.out.println(players[oppIdx].name + "荣和\t1000以上");
            }
        }

        System.out.println("==============================");

        // 3. Safe points for dealing to others
        for (int oppIdx = 0; oppIdx < 4; oppIdx++) {
            if (oppIdx == targetIdx) continue;
            int safePoints = findSafeDealPoints(targetIdx, oppIdx, baseline);
            if (safePoints >= YAKUMAN) {
                System.out.println("对" + players[oppIdx].name + "放铳\t" + formatYakuman());
            } else if (safePoints > 0) {
                System.out.println("对" + players[oppIdx].name + "放铳\t" + safePoints + "以下");
            } else {
                System.out.println("对" + players[oppIdx].name + "放铳\t0以下");
            }
        }

        System.out.println("==============================");

        // 4. Tsumo safe zones
        for (int oppIdx = 0; oppIdx < 4; oppIdx++) {
            if (oppIdx == targetIdx) continue;
            int maxTsumo = findMaxTsumoAgainst(targetIdx, oppIdx, baseline);
            String suffix = players[oppIdx].seat == EAST ? "亲家" : "";
            if (maxTsumo >= YAKUMAN) {
                System.out.println("被" + players[oppIdx].name + suffix + "自摸\t" + formatYakuman() + "all以下");
            } else if (maxTsumo > 0) {
                int childPay = maxTsumo / 3;
                int parentPay = maxTsumo / 3;
                System.out.println("被" + players[oppIdx].name + suffix + "自摸\t" + childPay + "・" + parentPay + "以下");
            } else {
                System.out.println("被" + players[oppIdx].name + suffix + "自摸\t0以下");
            }
        }

        System.out.println();

        // 5. Danger zones
        System.out.println(target.name + "危险区间:");
        printDangerZones(targetIdx, baseline);
    }

    static int findMinTsumo(int playerIdx, ScoreResult baseline) {
        int low = 0, high = YAKUMAN;

        while (low < high) {
            int mid = (low + high) / 2;
            if (mid == 0) mid = 1;

            int[] newScores = simulateTsumo(baseline.scores, playerIdx, mid);
            ScoreResult result = calculateWithScores(newScores);
            if (advances(result, playerIdx)) {
                high = mid;
            } else {
                low = mid + 1;
            }
            if (low >= high - 1) break;
        }

        if (low >= YAKUMAN) return YAKUMAN;

        int[] newScores = simulateTsumo(baseline.scores, playerIdx, low);
        ScoreResult result = calculateWithScores(newScores);
        if (!advances(result, playerIdx)) low++;

        return low;
    }

    static int findMinRonForTarget(int targetIdx, int dealerIdx, ScoreResult baseline) {
        int low = 0, high = YAKUMAN;

        while (low < high) {
            int mid = (low + high) / 2;
            if (mid == 0) mid = 1;

            int[] newScores = simulateRon(baseline.scores, targetIdx, dealerIdx, mid);
            ScoreResult result = calculateWithScores(newScores);
            if (advances(result, targetIdx)) {
                high = mid;
            } else {
                low = mid + 1;
            }
            if (low >= high - 1) break;
        }

        if (low >= YAKUMAN) return YAKUMAN;

        int[] newScores = simulateRon(baseline.scores, targetIdx, dealerIdx, low);
        ScoreResult result = calculateWithScores(newScores);
        if (!advances(result, targetIdx)) low++;

        return low;
    }

    static int findSafeDealPoints(int targetIdx, int oppIdx, ScoreResult baseline) {
        int low = 0, high = YAKUMAN;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            int[] newScores = simulateRon(baseline.scores, oppIdx, targetIdx, mid);
            ScoreResult result = calculateWithScores(newScores);
            if (advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }
            if (low >= high - 1) break;
        }

        int[] newScores = simulateRon(baseline.scores, oppIdx, targetIdx, low);
        ScoreResult result = calculateWithScores(newScores);
        if (!advances(result, targetIdx)) low--;

        return low;
    }

    static int findMaxTsumoAgainst(int targetIdx, int oppIdx, ScoreResult baseline) {
        int low = 0, high = YAKUMAN;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            int[] newScores = simulateTsumo(baseline.scores, oppIdx, mid);
            ScoreResult result = calculateWithScores(newScores);
            if (advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }
            if (low >= high - 1) break;
        }

        int[] newScores = simulateTsumo(baseline.scores, oppIdx, low);
        ScoreResult result = calculateWithScores(newScores);
        if (!advances(result, targetIdx)) low--;

        return low;
    }

    static void printDangerZones(int targetIdx, ScoreResult baseline) {
        boolean hasDanger = false;

        for (int gainerIdx = 0; gainerIdx < 4; gainerIdx++) {
            if (gainerIdx == targetIdx) continue;
            for (int loserIdx = 0; loserIdx < 4; loserIdx++) {
                if (loserIdx == targetIdx || loserIdx == gainerIdx) continue;

                int threshold = findDangerThreshold(targetIdx, gainerIdx, loserIdx, baseline);
                if (threshold > 0 && threshold < YAKUMAN) {
                    hasDanger = true;
                    System.out.println(players[gainerIdx].name + "点" + players[loserIdx].name + 
                        "\t" + threshold + "以上会丢晋级资格");
                } else if (threshold >= YAKUMAN) {
                    hasDanger = true;
                    System.out.println(players[gainerIdx].name + "点" + players[loserIdx].name + 
                        "\t" + formatYakuman() + "以上3倍役满以下会丢晋级资格");
                }
            }
        }

        if (!hasDanger) {
            System.out.println("(无危险区间)");
        }
    }

    static int findDangerThreshold(int targetIdx, int gainerIdx, int loserIdx, ScoreResult baseline) {
        int low = 0, high = TRIPLE_YAKUMAN;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            int[] newScores = simulateHorizontal(baseline.scores, loserIdx, gainerIdx, mid);
            ScoreResult result = calculateWithScores(newScores);
            if (!advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }
            if (low >= high - 1) break;
        }

        if (low >= TRIPLE_YAKUMAN) return TRIPLE_YAKUMAN;

        int[] newScores = simulateHorizontal(baseline.scores, loserIdx, gainerIdx, low);
        ScoreResult result = calculateWithScores(newScores);
        if (!advances(result, targetIdx)) low++;

        return low;
    }

    static String formatYakuman() {
        return "役满";
    }

    static void printDrawBranches(ScoreResult baseline) {
        System.out.println("【听牌分支一览】");

        Set<String> currentlyAdvancing = new LinkedHashSet<>();
        for (int i = 0; i < 4; i++) {
            if (advances(baseline, i)) {
                currentlyAdvancing.add(players[i].name);
            }
        }
        String advancingStr = "[" + String.join(", ", currentlyAdvancing) + "]晋级";

        System.out.println("全员未听牌：" + advancingStr);
        System.out.println("全员听牌：" + advancingStr);

        for (int i = 0; i < 4; i++) {
            System.out.println(players[i].name + "一人听牌：" + advancingStr);
            System.out.println(players[i].name + "一人未听牌：" + advancingStr);
        }

        for (int i = 0; i < 4; i++) {
            for (int j = i + 1; j < 4; j++) {
                System.out.println(players[i].name + "、" + players[j].name + "听牌：" + advancingStr);
            }
        }
    }
