            int maxRon = findMaxRon(targetIdx, oppIdx, currentTotals, rankingPoints, advancementCount, rule);
            if (maxRon > 0) {
                System.out.println(players[oppIdx].name + "荣和\t" + formatPoints(maxRon) + "以上");
            } else if (maxRon == 0) {
