        // 4. Danger zones
        System.out.println(target.name + "危险区间:");
        printDangerZones(targetIdx, currentTotals, rankingPoints, advancementCount, rule, players);
    }

    static int findMinSelfDraw(int playerIdx, double[] currentTotals, double[] rankingPoints, 
            int advancementCount, String rule) {

        // Binary search for minimum self-draw points needed
        int low = 0, high = 100000;
        int startPoints = Player.getStartPoints(rule);

        // Current score changes
        int baseScore = players[playerIdx].currentScore;

        while (low < high) {
            int mid = (low + high) / 2;
            if (mid == 0) mid = 1;

            // Simulate self-draw of 'mid' points
            double[] newTotals = simulateScoreChange(currentTotals, playerIdx, -1, mid, true, rule);
            double[] newRankingPoints = calculateNewRankingPoints(newTotals, rankingPoints);
            double[] finalTotals = addRankingPoints(newTotals, newRankingPoints);

            if (advances(finalTotals, playerIdx, advancementCount)) {
                high = mid;
            } else {
                low = mid + 1;
            }

            if (low >= high) break;
        }

        return low <= 100000 ? low : -1;
    }

    static int findMaxRon(int targetIdx, int dealerIdx, double[] currentTotals, 
            double[] rankingPoints, int advancementCount, String rule) {

        // Binary search for maximum ron points that still allows target to advance
        int low = 0, high = 80000;
        int startPoints = Player.getStartPoints(rule);

        while (low < high) {
            int mid = (low + high + 1) / 2;

            // Simulate dealerIdx dealing into targetIdx for 'mid' points
            double[] newTotals = simulateRon(currentTotals, targetIdx, dealerIdx, mid, rule);
            double[] newRankingPoints = calculateNewRankingPoints(newTotals, rankingPoints);
            double[] finalTotals = addRankingPoints(newTotals, newRankingPoints);

