        }
    }

    static int findDangerThreshold(int targetIdx, int gainerIdx, int loserIdx, 
            double[] currentTotals, double[] rankingPoints, int advancementCount, String rule) {

        // Binary search for threshold where horizontal movement causes target to lose advancement
        int low = 0, high = 100000;

        while (low < high) {
