{"content": "import java.util.*;
import java.io.*;

/**
 * 立直麻将晋级条件计算器
 * Riichi Mahjong Advancement Condition Calculator
 */
public class RiichiCalculator {

    // Seat indices
    public static final int EAST = 0, SOUTH = 1, WEST = 2, NORTH = 3;

    // Rule types
    public static final String RULE_M_LEAGUE = "M-league";
    public static final String RULE_A = "A规";
    public static final String RULE_WRC = "WRC规";
    public static final String RULE_SAIKOU = "最高位规";

    static class Player {
        String name;
        int seat; // 0=East, 1=South, 2=West, 3=North
        int currentScore;
        double preGameTotal; // Total points before this game

        Player(String name, int seat, int currentScore, double preGameTotal) {
            this.name = name;
            this.seat = seat;
            this.currentScore = currentScore;
            this.preGameTotal = preGameTotal;
        }
    }

    static class ScoreResult {
        double[] preliminary; // (score - startPoints) / 1000
        int[] ranking; // Ranking order (0=1st, 3=4th)
        double[] finalTotals;

        ScoreResult(double[] preliminary, int[] ranking, double[] finalTotals) {
            this.preliminary = preliminary;
            this.ranking = ranking;
            this.finalTotals = finalTotals;
        }
    }

    static Player[] players;
    static int[] seatToIndex = new int[4];
    static int dealer;
    static String rule;
    static int taku;
    static int honba;
    static int advancementCount;
    static int startPoints;
    static double[] rankingPoints;

    public static void main(String[] args) throws Exception {
        Scanner scanner = new Scanner(System.in);

        // Parse input
        String dealerLine = scanner.nextLine().trim();
        dealer = parseSeat(dealerLine.substring(dealerLine.indexOf("：") + 1).trim());

        String[] seats = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        String[] names = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        String[] preTotals = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        String[] scores = scanner.nextLine().trim().split("：")[1].trim().split("\\s+");
        advancementCount = Integer.parseInt(scanner.nextLine().trim().split("：")[1].trim());
        rule = scanner.nextLine().trim().split("：")[1].trim();
        taku = Integer.parseInt(scanner.nextLine().trim().split("：")[1].trim());
        honba = Integer.parseInt(scanner.nextLine().trim().split("：")[1].trim());

        players = new Player[4];

        for (int i = 0; i < 4; i++) {
            int seatIndex = parseSeat(seats[i]);
            seatToIndex[seatIndex] = i;
            players[i] = new Player(names[i], seatIndex, 
                Integer.parseInt(scores[i]), Double.parseDouble(preTotals[i]));
        }

        startPoints = getStartPoints(rule);
        rankingPoints = getRankingPoints(rule);

        // Calculate and output results
        ScoreResult baseline = calculateCurrentResult();

        // For each player, calculate conditions
        for (int targetIdx = 0; targetIdx < 4; targetIdx++) {
            printPlayerConditions(targetIdx, baseline);
            System.out.println();
        }

        // Draw (流局) branches
        printDrawBranches(baseline);
    }

    static int parseSeat(String s) {
        switch (s) {
            case "东": case "東": return EAST;
            case "南": return SOUTH;
            case "西": return WEST;
            case "北": return NORTH;
            default: return EAST;
        }
    }

    static int getStartPoints(String rule) {
        switch (rule) {
            case RULE_M_LEAGUE: return 25000;
            case RULE_A:
            case RULE_WRC:
            case RULE_SAIKOU: return 30000;
            default: return 25000;
        }
    }

    static double[] getRankingPoints(String rule) {
        switch (rule) {
            case RULE_M_LEAGUE: return new double[]{50.0, 10.0, -10.0, -30.0};
            case RULE_SAIKOU: return new double[]{12.0, 4.0, -4.0, -12.0};
            case RULE_A: return new double[]{20.0, 10.0, -10.0, -20.0};
            case RULE_WRC: return new double[]{30.0, 10.0, -10.0, -30.0};
            default: return new double[]{50.0, 10.0, -10.0, -30.0};
        }
    }

    static ScoreResult calculateCurrentResult() {
        double[] preliminary = new double[4];
        for (int i = 0; i < 4; i++) {
            preliminary[i] = (players[i].currentScore - startPoints) / 1000.0;
        }

        double[] totals = new double[4];
        for (int i = 0; i < 4; i++) {
            totals[i] = preliminary[i] + players[i].preGameTotal;
        }

        int[] ranking = calculateRanking(totals);

        double[] finalTotals = new double[4];
        for (int i = 0; i < 4; i++) {
            finalTotals[i] = totals[i] + rankingPoints[ranking[i]];
        }

        return new ScoreResult(preliminary, ranking, finalTotals);
    }

    static int[] calculateRanking(double[] totals) {
        Integer[] order = new Integer[]{0, 1, 2, 3};
        Arrays.sort(order, (a, b) -> Double.compare(totals[b], totals[a]));

        int[] ranking = new int[4];
        for (int i = 0; i < 4; i++) {
            ranking[order[i]] = i;
        }
        return ranking;
    }

    static ScoreResult simulateAndCalculate(int winner, int loser, int points, boolean isTsumo) {
        int[] newScores = new int[4];
        for (int i = 0; i < 4; i++) {
            newScores[i] = players[i].currentScore;
        }

        if (isTsumo) {
            // Winner gains 'points' from 3 losers
            int perPerson = points / 3;
            int remainder = points % 3;
            newScores[winner] += points;
            for (int i = 0; i < 3; i++) {
                int loserIdx = (winner + i + 1) % 4;
                int payment = perPerson;
                if (i < remainder) payment++;
                newScores[loserIdx] -= payment;
            }
        } else {
            // Ron: winner gains from loser
            newScores[winner] += points;
            newScores[loser] -= points;
        }

        double[] preliminary = new double[4];
        for (int i = 0; i < 4; i++) {
            preliminary[i] = (newScores[i] - startPoints) / 1000.0;
        }

        double[] totals = new double[4];
        for (int i = 0; i < 4; i++) {
            totals[i] = preliminary[i] + players[i].preGameTotal;
        }

        int[] ranking = calculateRanking(totals);

        double[] finalTotals = new double[4];
        for (int i = 0; i < 4; i++) {
            finalTotals[i] = totals[i] + rankingPoints[ranking[i]];
        }

        return new ScoreResult(preliminary, ranking, finalTotals);
    }

    static ScoreResult simulateHorizontal(int giver, int receiver, int points) {
        int[] newScores = new int[4];
        for (int i = 0; i < 4; i++) {
            newScores[i] = players[i].currentScore;
        }

        newScores[receiver] += points;
        newScores[giver] -= points;

        double[] preliminary = new double[4];
        for (int i = 0; i < 4; i++) {
            preliminary[i] = (newScores[i] - startPoints) / 1000.0;
        }

        double[] totals = new double[4];
        for (int i = 0; i < 4; i++) {
            totals[i] = preliminary[i] + players[i].preGameTotal;
        }

        int[] ranking = calculateRanking(totals);

        double[] finalTotals = new double[4];
        for (int i = 0; i < 4; i++) {
            finalTotals[i] = totals[i] + rankingPoints[ranking[i]];
        }

        return new ScoreResult(preliminary, ranking, finalTotals);
    }

    static boolean advances(ScoreResult result, int playerIdx) {
        double playerTotal = result.finalTotals[playerIdx];
        int count = 0;
        for (int i = 0; i < 4; i++) {
            if (result.finalTotals[i] >= playerTotal - 0.001) count++;
        }
        return count <= advancementCount;
    }

    static void printPlayerConditions(int targetIdx, ScoreResult baseline) {
        Player target = players[targetIdx];
        System.out.println(target.name + "晋级条件");

        // 1. Self-draw (自摸) conditions
        int minSelfDraw = findMinSelfDraw(targetIdx, baseline);
        if (minSelfDraw > 0) {
            System.out.println("自摸\t" + formatThreshold(minSelfDraw) + "以上");
        } else if (minSelfDraw == 0) {
            System.out.println("自摸\talready advancing");
        } else {
            System.out.println("自摸\timpossible");
        }

        System.out.println("==============================");

        // 2. Ron conditions (being dealt into by others)
        for (int oppIdx = 0; oppIdx < 4; oppIdx++) {
            if (oppIdx == targetIdx) continue;
            int maxRon = findMaxRon(targetIdx, oppIdx, baseline);
            if (maxRon >= 80000) {
                System.out.println(players[oppIdx].name + "荣和\t" + formatYakuman() + "以上");
            } else if (maxRon > 0) {
                System.out.println(players[oppIdx].name + "荣和\t" + formatThreshold(maxRon) + "以上");
            } else if (maxRon == 0) {
                System.out.println(players[oppIdx].name + "荣和\tany");
            } else {
                System.out.println(players[oppIdx].name + "荣和\timpossible");
            }
        }

        System.out.println("==============================");

        // 3. Safe from others' tsumo
        for (int oppIdx = 0; oppIdx < 4; oppIdx++) {
            if (oppIdx == targetIdx) continue;
            int maxTsumoAgainst = findMaxTsumoAgainst(targetIdx, oppIdx, baseline);
            String suffix = players[oppIdx].seat == EAST ? "亲家" : "";
            if (maxTsumoAgainst >= 80000) {
                System.out.println("被" + players[oppIdx].name + suffix + "自摸\t" + formatYakuman() + "以上");
            } else if (maxTsumoAgainst > 0) {
                System.out.println("被" + players[oppIdx].name + suffix + "自摸\t" + formatThreshold(maxTsumoAgainst) + "以下");
            } else {
                System.out.println("被" + players[oppIdx].name + suffix + "自摸\timpossible");
            }
        }

        System.out.println();

        // 4. Danger zones
        System.out.println(target.name + "危险区间:");
        printDangerZones(targetIdx, baseline);
    }

    static int findMinSelfDraw(int playerIdx, ScoreResult baseline) {
        // Binary search for minimum self-draw points needed
        int low = 0, high = 80000;

        while (low < high) {
            int mid = (low + high) / 2;
            if (mid == 0) mid = 1;

            ScoreResult result = simulateAndCalculate(playerIdx, -1, mid, true);
            if (advances(result, playerIdx)) {
                high = mid;
            } else {
                low = mid + 1;
            }

            if (low >= high - 1) break;
        }

        if (low > 80000) return -1;

        // Verify that low actually works
        ScoreResult result = simulateAndCalculate(playerIdx, -1, low, true);
        return advances(result, playerIdx) ? low : low + 1;
    }

    static int findMaxRon(int targetIdx, int dealerIdx, ScoreResult baseline) {
        // Binary search for maximum ron points that still allows target to advance
        int low = 0, high = 80000;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            ScoreResult result = simulateAndCalculate(targetIdx, dealerIdx, mid, false);
            if (advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high - 1) break;
        }

        // Verify that low works
        ScoreResult result = simulateAndCalculate(targetIdx, dealerIdx, low, false);
        return advances(result, targetIdx) ? low : low - 1;
    }

    static int findMaxTsumoAgainst(int targetIdx, int oppIdx, ScoreResult baseline) {
        // Binary search for maximum tsumo points from oppIdx that still allows target to advance
        int low = 0, high = 80000;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            ScoreResult result = simulateAndCalculate(oppIdx, targetIdx, mid, true);
            if (advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high - 1) break;
        }

        ScoreResult result = simulateAndCalculate(oppIdx, targetIdx, low, true);
        return advances(result, targetIdx) ? low : low - 1;
    }

    static void printDangerZones(int targetIdx, ScoreResult baseline) {
        boolean hasDanger = false;

        // For each pair of other players, check if horizontal movement can dislodge target
        for (int gainerIdx = 0; gainerIdx < 4; gainerIdx++) {
            if (gainerIdx == targetIdx) continue;
            for (int loserIdx = 0; loserIdx < 4; loserIdx++) {
                if (loserIdx == targetIdx || loserIdx == gainerIdx) continue;

                int threshold = findDangerThreshold(targetIdx, gainerIdx, loserIdx, baseline);
                if (threshold > 0) {
                    hasDanger = true;
                    String yakumanCond = threshold >= 80000 ? "3倍役满以下" : "";
                    System.out.println(players[gainerIdx].name + "点" + players[loserIdx].name + 
                        "\t" + formatThreshold(threshold) + "以上" + yakumanCond + "会丢晋级资格");
                }
            }
        }

        if (!hasDanger) {
            System.out.println("(无危险区间)");
        }
    }

    static int findDangerThreshold(int targetIdx, int gainerIdx, int loserIdx, ScoreResult baseline) {
