        printDangerZones(targetIdx, baseline);
    }

    static int findMinSelfDraw(int playerIdx, ScoreResult baseline) {
        // Binary search for minimum self-draw points needed
        int low = 0, high = 80000;

        while (low < high) {
            int mid = (low + high) / 2;
            if (mid == 0) mid = 1;

            ScoreResult result = simulateAndCalculate(playerIdx, -1, mid, true);
            if (advances(result, playerIdx)) {
                high = mid;
            } else {
                low = mid + 1;
            }

            if (low >= high - 1) break;
        }

        if (low > 80000) return -1;

        // Verify that low actually works
        ScoreResult result = simulateAndCalculate(playerIdx, -1, low, true);
        return advances(result, playerIdx) ? low : low + 1;
    }

    static int findMaxRon(int targetIdx, int dealerIdx, ScoreResult baseline) {
        // Binary search for maximum ron points that still allows target to advance
        int low = 0, high = 80000;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            ScoreResult result = simulateAndCalculate(targetIdx, dealerIdx, mid, false);
            if (advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high - 1) break;
        }

        // Verify that low works
        ScoreResult result = simulateAndCalculate(targetIdx, dealerIdx, low, false);
        return advances(result, targetIdx) ? low : low - 1;
    }

    static int findMaxTsumoAgainst(int targetIdx, int oppIdx, ScoreResult baseline) {
        // Binary search for maximum tsumo points from oppIdx that still allows target to advance
        int low = 0, high = 80000;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            ScoreResult result = simulateAndCalculate(oppIdx, targetIdx, mid, true);
            if (advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high - 1) break;
        }

        ScoreResult result = simulateAndCalculate(oppIdx, targetIdx, low, true);
        return advances(result, targetIdx) ? low : low - 1;
    }

    static void printDangerZones(int targetIdx, ScoreResult baseline) {
        boolean hasDanger = false;

        // For each pair of other players, check if horizontal movement can dislodge target
        for (int gainerIdx = 0; gainerIdx < 4; gainerIdx++) {
            if (gainerIdx == targetIdx) continue;
            for (int loserIdx = 0; loserIdx < 4; loserIdx++) {
                if (loserIdx == targetIdx || loserIdx == gainerIdx) continue;

                int threshold = findDangerThreshold(targetIdx, gainerIdx, loserIdx, baseline);
                if (threshold > 0) {
                    hasDanger = true;
                    String yakumanCond = threshold >= 80000 ? "3倍役满以下" : "";
                    System.out.println(players[gainerIdx].name + "点" + players[loserIdx].name + 
                        "\t" + formatThreshold(threshold) + "以上" + yakumanCond + "会丢晋级资格");
                }
            }
        }

        if (!hasDanger) {
            System.out.println("(无危险区间)");
        }
    }

    static int findDangerThreshold(int targetIdx, int gainerIdx, int loserIdx, ScoreResult baseline) {
        // Binary search for threshold where horizontal movement causes target to lose advancement
        int low = 0, high = 80000;

        while (low < high) {
            int mid = (low + high + 1) / 2;

            ScoreResult result = simulateHorizontal(gainerIdx, loserIdx, mid);
            if (!advances(result, targetIdx)) {
                low = mid;
            } else {
                high = mid - 1;
            }

            if (low >= high - 1) break;
        }

        ScoreResult result = simulateHorizontal(gainerIdx, loserIdx, low);
        return !advances(result, targetIdx) ? low : low - 1;
    }

    static String formatThreshold(int points) {
        if (points >= 80000) {
            return "役满";
        }
        return points + "";
    }

    static String formatYakuman() {
        return "役满";
    }

    static void printDrawBranches(ScoreResult baseline) {
        System.out.println("【听牌分支一览】");

        Set<String> currentlyAdvancing = new LinkedHashSet<>();
        for (int i = 0; i < 4; i++) {
            if (advances(baseline, i)) {
                currentlyAdvancing.add(players[i].name);
            }
        }
        String advancingStr = "[" + String.join(", ", currentlyAdvancing) + "]晋级";

        // All noten
        System.out.println("全员未听牌：" + advancingStr);

        // All tenpai
        System.out.println("全员听牌：" + advancingStr + "，但kagayaki听牌而继续");

        // Individual cases
        for (int i = 0; i < 4; i++) {
            System.out.println(players[i].name + "一人听牌：" + advancingStr);
            System.out.println(players[i].name + "一人未听牌：" + advancingStr + "，但kagayaki听牌而继续");
        }

        // Pairs
        for (int i = 0; i < 4; i++) {
            for (int j = i + 1; j < 4; j++) {
                System.out.println(players[i].name + "、" + players[j].name + "听牌：" + advancingStr);
            }
        }
    }
}
